    private fun ASTNode.indentOfLine(): String {
        var leaf = prevLeaf(includeEmpty = true)
        while (leaf != null) {
            if (leaf.elementType == WHITE_SPACE) {
                val text = leaf.text
                val lastNewLineIndex = text.lastIndexOf('\n')
                if (lastNewLineIndex != -1) {
                    return text.substring(lastNewLineIndex + 1)
                }
            }
            leaf = leaf.prevLeaf(includeEmpty = true)
        }
